{
  "mode": "method",
  "tests": [
    {
      "name": "search_role_admin",
      "input": {
        "searchTerm": "admin"
      },
      "output": [
        {
          "roleName": "admin"
        }
      ],
      "notes": "Validates that searching for 'admin' returns only roles with the name 'admin'."
    },
    {
      "name": "search_role_admin_invalid",
      "input": {
        "searchTerm": "user"
      },
      "output": [],
      "notes": "Ensures that searching for 'user' returns no roles related to 'admin'."
    },
    {
      "name": "edit_billing_account_payment_terms_disabled",
      "input": {
        "accountId": "12345"
      },
      "output": {
        "paymentTermsField": "disabled"
      },
      "notes": "Checks that the payment terms field is disabled on the billing account page."
    },
    {
      "name": "remove_reviewer_button_absent",
      "input": {
        "challengeId": "challenge_1"
      },
      "output": {
        "removeReviewerButton": false
      },
      "notes": "Confirms that the 'Remove Reviewer' button is no longer present."
    },
    {
      "name": "user_management_button_present",
      "input": {
        "challengeId": "challenge_1"
      },
      "output": {
        "userManagementButton": true
      },
      "notes": "Validates that the 'User Management' button is present on the page."
    },
    {
      "name": "search_role_empty_input",
      "input": {
        "searchTerm": ""
      },
      "output": [],
      "notes": "Tests that an empty search term returns no results."
    },
    {
      "name": "edit_billing_account_invalid_access",
      "input": {
        "accountId": "invalid_id"
      },
      "output": {
        "error": "Account not found"
      },
      "notes": "Checks that trying to edit a non-existent account returns an error."
    },
    {
      "name": "remove_reviewer_button_access_denied",
      "input": {
        "challengeId": "challenge_2",
        "userRole": "viewer"
      },
      "output": {
        "error": "Access denied"
      },
      "notes": "Ensures that a user without proper permissions cannot access the remove reviewer functionality."
    }
  ],
  "assumptions": "All tests assume the system is in a stable state and the user has the necessary permissions.",
  "notes": "Tests cover both functional requirements and edge cases to ensure robustness."
}
